import { getAdminSupabaseClient } from '@/utils/supabase-admin'

export interface AdminContactConfig {
    wechat_id: string
    wechat_qr: string
    telegram_id: string
    telegram_qr: string
    service_time: string
}

export const adminSystemApi = {
    /**
     * 获取联系方式配置
     */
    async getContactConfig(): Promise<{ success: boolean; data?: AdminContactConfig; error?: string }> {
        const client = getAdminSupabaseClient()

        const { data, error } = await client
            .from('system_configs')
            .select('value')
            .eq('key', 'contact_info')
            .single()

        if (error) {
            // PGRST116: No matching row found
            if (error.code === 'PGRST116') {
                 return {
                    success: true,
                    data: {
                        wechat_id: 'Spotify-cn',
                        wechat_qr: '',
                        telegram_id: '@Fantula_Support',
                        telegram_qr: '',
                        service_time: '10:00 - 23:00'
                    }
                }
            }
            return { success: false, error: error.message }
        }

        return { success: true, data: data.value }
    },

    /**
     * 更新联系方式配置
     */
    async updateContactConfig(config: AdminContactConfig): Promise<{ success: boolean; error?: string }> {
        const client = getAdminSupabaseClient()

        const { error } = await client
            .from('system_configs')
            .upsert({
                key: 'contact_info',
                value: config,
                updated_at: new Date().toISOString()
            })

        if (error) return { success: false, error: error.message }
        return { success: true }
    }
}
<template>
  <div class="contact-uploader">
    <div class="uploader-wrapper">
        <el-upload
            class="upload-demo"
            action="#"
            :show-file-list="false"
            :http-request="handleUpload"
            :disabled="uploading"
            accept="image/*"
        >
            <div v-if="modelValue" class="preview-container">
                <el-image :src="modelValue" fit="contain" class="preview-image" />
                <div class="overlay">
                    <el-icon><Edit /></el-icon>
                    <span>更换图片</span>
                </div>
            </div>
            <div v-else class="upload-placeholder">
                <el-icon class="icon"><Plus /></el-icon>
                <span class="text">点击上传</span>
            </div>
        </el-upload>
    </div>
    <div class="upload-tip" v-if="tip">{{ tip }}</div>
  </div>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import { Plus, Edit } from '@element-plus/icons-vue'
import { getAdminSupabaseClient } from '@/utils/supabase-admin'
import { ElMessage } from 'element-plus'

const props = defineProps<{
    modelValue: string
    folder?: string
    tip?: string
}>()

const emit = defineEmits(['update:modelValue'])

const uploading = ref(false)

const handleUpload = async (options: any) => {
    const file = options.file
    const folder = props.folder || 'contact_materials'

    // Validate file type
    if (!file.type.startsWith('image/')) {
        ElMessage.error('请上传图片文件')
        return
    }

    uploading.value = true
    const client = getAdminSupabaseClient()

    try {
        const fileName = `${Date.now()}_${file.name.replace(/[^a-zA-Z0-9.]/g, '')}`
        const filePath = `${folder}/${fileName}`

        // Upload to 'media' bucket (assuming 'media' is the standard public bucket, or 'public')
        // Trying 'media' first as per common convention, or check 'storage' bucket?
        // User docs mentioned "Material Library" (R2 or Supabase).
        // Let's assume standard 'media' bucket for now.
        const bucket = 'media' 

        const { data, error } = await client
            .storage
            .from(bucket)
            .upload(filePath, file, {
                cacheControl: '3600',
                upsert: false
            })

        if (error) throw error

        // Get Public URL
        const { data: { publicUrl } } = client
            .storage
            .from(bucket)
            .getPublicUrl(filePath)

        if (publicUrl) {
            emit('update:modelValue', publicUrl)
            ElMessage.success('上传成功')
        }
    } catch (e: any) {
        console.error('Upload failed', e)
        ElMessage.error(e.message || '上传失败，请检查存储配置')
    } finally {
        uploading.value = false
    }
}
</script>

<style scoped>
.uploader-wrapper {
    width: 120px;
    height: 120px;
    border: 1px dashed #dcdfe6;
    border-radius: 6px;
    cursor: pointer;
    overflow: hidden;
    transition: border-color 0.2s;
    background: #fafafa;
}
.uploader-wrapper:hover {
    border-color: #409eff;
}
.upload-placeholder {
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    color: #909399;
}
.icon { font-size: 24px; margin-bottom: 8px; }
.text { font-size: 12px; }

.preview-container {
    width: 100%;
    height: 100%;
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
}
.preview-image {
    width: 100%;
    height: 100%;
    object-fit: contain;
}
.overlay {
    position: absolute;
    inset: 0;
    background: rgba(0,0,0,0.5);
    color: #fff;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: opacity 0.2s;
}
.preview-container:hover .overlay { opacity: 1; }
.upload-tip {
    font-size: 12px;
    color: #909399;
    margin-top: 4px;
}
</style>

import { ref, onMounted } from 'vue'
import { adminSystemApi, type AdminContactConfig } from '@/api/admin'
import { ElMessage } from 'element-plus'

export function useAdminContactConfig() {
    const loading = ref(false)
    const saving = ref(false)
    const form = ref<AdminContactConfig>({
        wechat_id: '',
        wechat_qr: '',
        telegram_id: '',
        telegram_qr: '',
        service_time: ''
    })

    const loadConfig = async () => {
        loading.value = true
        try {
            const res = await adminSystemApi.getContactConfig()
            if (res.success && res.data) {
                form.value = { ...form.value, ...res.data }
            } else {
                // FALLBACK: Use static assets if DB is empty or fails (e.g. Schema Cache issue)
                // This ensures the UI looks correct immediately for the user.
                console.warn('Using static defaults due to DB missing/error', res.error)
                form.value = {
                    wechat_id: 'Spotify-cn',
                    wechat_qr: '/images/contact/wechat_qr.jpg',
                    telegram_id: '@FANTULA_SUPPORT',
                    telegram_qr: '/images/contact/telegram_qr.jpg',
                    service_time: '10:00 - 23:00'
                }
            }
        } catch (e: any) {
            ElMessage.error(e.message || '加载配置失败')
        } finally {
            loading.value = false
        }
    }

    const saveConfig = async () => {
        saving.value = true
        try {
            const res = await adminSystemApi.updateContactConfig(form.value)
            if (res.success) {
                ElMessage.success('配置已保存')
            } else {
                ElMessage.error(res.error || '保存失败')
            }
        } catch (e: any) {
            ElMessage.error(e.message || '保存异常')
        } finally {
            saving.value = false
        }
    }

    onMounted(() => {
        loadConfig()
    })

    return {
        form,
        loading,
        saving,
        loadConfig,
        saveConfig
    }
}
<template>
  <div class="page-container">
    <PageTipHeader 
      title="联系方式设置" 
      description="管理前台显示的微信、Telegram及在线时间信息。内容将实时同步至 PC 端及移动端显示。" 
    />

    <StickyFormHeader 
      title="联系方式" 
      subtitle="配置中心"
      :loading="saving"
      @save="saveConfig"
      :show-back="false"
    />

    <el-card shadow="never" class="mt-4" v-loading="loading">
      <el-form :model="form" label-width="120px" class="py-4">

        <!-- Service Time -->
        <el-row>
          <el-col :span="24">
            <h3 class="section-title">🕒 服务时间设置</h3>
            <el-form-item label="在线服务时间">
               <el-input v-model="form.service_time" placeholder="例如: 10:00 - 23:00" style="max-width: 400px"/>
               <div class="form-tip">显示在已联系客服弹窗中的服务时间提示</div>
            </el-form-item>
          </el-col>
        </el-row>

        <el-divider />

        <!-- PC Settings -->
        <h3 class="section-title">🖥️ PC 端设置 (Modal)</h3>
        <div class="p-4 bg-gray-50 rounded mb-6">
            <el-row :gutter="40">
                <el-col :span="12">
                     <div class="sub-title">微信客服 (WeChat)</div>
                     <el-form-item label="微信号 / ID">
                        <el-input v-model="form.wechat_id" placeholder="Spotify-cn" />
                     </el-form-item>
                     <el-form-item label="微信二维码">
                        <ContactImageUploader v-model="form.wechat_qr" folder="contact_materials" tip="建议尺寸: 300x300" />
                     </el-form-item>
                </el-col>
                <el-col :span="12">
                     <div class="sub-title">Telegram 客服</div>
                     <el-form-item label="用户名 / ID">
                        <el-input v-model="form.telegram_id" placeholder="@Fantula_Support" />
                     </el-form-item>
                     <el-form-item label="Telegram二维码">
                        <ContactImageUploader v-model="form.telegram_qr" folder="contact_materials" tip="建议尺寸: 300x300" />
                     </el-form-item>
                </el-col>
            </el-row>
        </div>

        <el-divider />

        <!-- Mobile Settings (Read Only or Sync explanation) -->
         <h3 class="section-title">📱 移动端设置 (H5)</h3>
         <div class="p-4 bg-blue-50 rounded">
            <el-alert title="移动端自动同步" type="info" :closable="false" show-icon>
                <template #default>
                    移动端将自动复用上述配置信息。
                    <ul>
                        <li><strong>微信号/TG号</strong>: 点击可直接复制。</li>
                        <li><strong>二维码</strong>: 移动端暂不展示二维码，仅展示文本ID。</li>
                    </ul>
                </template>
            </el-alert>
         </div>

      </el-form>
    </el-card>
  </div>
</template>

<script setup lang="ts">
import PageTipHeader from '@/components/admin/base/PageTipHeader.vue'
import StickyFormHeader from '@/components/admin/base/StickyFormHeader.vue'
import ContactImageUploader from '@/components/admin/base/ContactImageUploader.vue'
import { useAdminContactConfig } from '@/composables/admin/useAdminContactConfig'

definePageMeta({
  layout: 'mgmt', // Mandatory strictly standard layout
  middleware: ["mgmt-auth"],
  title: '联系方式设置'
})

const { form, loading, saving, saveConfig } = useAdminContactConfig()
</script>

